var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"MANAGER_NPC_NULL_NULL","text":{"KOREA":"들어와. 보미야.","JPN":"ボミ、入っていいわよ。","ENG":"Come in, Bomi.","TWN":"進來吧，普美。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"안냐앙~♪ 나 찾았어, 매니저?","JPN":"こんにちにゃあ～♪　マネージャー、ボミを呼んだかにゃ？","ENG":"Hiya! ♪ Did you look for me, Manager?","TWN":"你好喵～♪你找我嗎，經紀人？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MANAGER_NPC_NULL_NULL","text":{"KOREA":"뭐니, 그 복장은......?","JPN":"ええっと、その格好は……？","ENG":"What's with the outfit?","TWN":"妳那是什麼打扮……？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"요즘 새로 구상하고 있는 안무를 위한 복장이야.","JPN":"最近考えてる新しい振り付けのためのコスチュームにゃ。","ENG":"It's a new costume for this dance I've been choreographing.","TWN":"這是我最近設計的最新舞蹈服裝。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"어때? 움직이기 편해 보이지 않냥?","JPN":"どうかにゃ？　動きやすそうに見えないかにゃ？","ENG":"What do you think? Doesn't it look comfy?","TWN":"怎麼樣？看起來是不是很容易活動？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MANAGER_NPC_NULL_NULL","text":{"KOREA":"하아......","JPN":"ふう……","ENG":"*Sigh*...","TWN":"唉……"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"궁금하면 지금 보여 줘도 상관없다냥♬","JPN":"気になるなら今から見せてあげてもいいにゃ♬","ENG":"If you're curious, I could show you the dance right now. ♬","TWN":"好奇的話，也不是不能現在就跳給你看喔喵♬"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"박자 넣어 볼까? 원♪ 투~♬","JPN":"ほいじゃリズムを取るにゃ！　ワン♪　ツ～♬","ENG":"Give me a beat, will you? One... ♪ Two... ♬","TWN":"要不要試著打一下節拍呢？一♪二～♬"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MANAGER_NPC_NULL_NULL","text":{"KOREA":"네 춤 솜씨는 잘 아니까 자리에 앉아.","JPN":"あなたの踊りのセンスはよくわかってるから、まずは座りなさい。","ENG":"I already know how well you can dance. Just have a seat please.","TWN":"我很清楚妳的舞蹈實力，坐下吧。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MANAGER_NPC_NULL_NULL","text":{"KOREA":"오늘은 춤 때문에 부른 게 아니야.","JPN":"今日はダンスのことで呼んだんじゃないの。","ENG":"I didn't ask to see you because of your dance today.","TWN":"今天把妳叫過來跟舞蹈無關。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"흐냐암~ 졸리는데 가서 자도 되냥?","JPN":"ふにゃあ～眠くなってきたにゃ。帰って寝てもいいかにゃ？","ENG":"*Yawn* I'm sleepy... Can I go take a nap now?","TWN":"哼喵～我有點睏了，我能回去睡覺了嗎喵？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MANAGER_NPC_NULL_NULL","text":{"KOREA":"문 열고 들어올 때까지만 해도 팔팔했잖아! 잠들지 말고 말 좀 들어!","JPN":"あなたは踊るか寝るかしかできないの！？　寝ないで話を聞きなさい！","ENG":"You were all energetic when you walked in just now! Stop dozing off and listen to me!","TWN":"妳開門的時候不是還生龍活虎的嗎！不准睡覺認真聽！"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MANAGER_NPC_NULL_NULL","text":{"KOREA":"넌 별 관심이 없었겠지만, 요새 사람들이 널 두고 이러쿵저러쿵 얘기가 많아.","JPN":"あなたは興味ないと思うけど、最近、あなたが原因で色んな噂が飛び交ってるのよ。","ENG":"You may not give a hoot, but people have been talking about you recently.","TWN":"雖然妳可能不在意，但最近人們可是一直在討論妳啊。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MANAGER_NPC_NULL_NULL","text":{"KOREA":"구체적으로는 네가 무대에서 공연하던 중에 그대로 잠들어 버린 뒤부터야.","JPN":"正確に言うと、あなたがライブステージで寝落ちしてしまったのが噂の発端になったの。","ENG":"To be more specific, this started after you fell sleep on stage a while ago.","TWN":"具體來說，就是妳在舞臺上演出時直接睡著之後。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MANAGER_NPC_NULL_NULL","text":{"KOREA":"언론에서는 계속 우리 회사가 멤버들을 혹사시킨다고 의심의 눈초리를 보내고 있어.","JPN":"うちの事務所がメンバーを酷使しているんじゃないかって、今じゃマスコミにまで疑いの目を向けられてるのよ。","ENG":"The press is saying the agency's been working you guys too hard.","TWN":"現在外界媒體都在懷疑我們公司在壓榨成員。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MANAGER_NPC_NULL_NULL","text":{"KOREA":"여러 차례 해명했지만...... 소속사 이미지가 말이 아니야.","JPN":"何度も釈明してるけど……事務所のイメージはガタ落ちよ。","ENG":"Although we tried to explain ourselves many times, the agency's taken a big hit to our reputation.","TWN":"雖然我們解釋過好幾次……但無奈所屬公司的大眾印象實在太不像話了。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"흠냐암......","JPN":"ふんにゃあぁ……","ENG":"*Yawn*...","TWN":"呼喵……"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MANAGER_NPC_NULL_NULL","text":{"KOREA":"......보미야. 내가 지금까지 무슨 얘기를 했지?","JPN":"……ねぇ、ボミ。今の話、ちゃんと聞いてたわよね？","ENG":"Bomi. Did you even hear a word I just said?","TWN":"……普美，妳有在聽我說話嗎？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"냐하하~ 그렇지만 난 데뷔 전에 미리 말했는데~","JPN":"にゃはは～。でも、ボミはデビュー前からちゃんと言ってたにゃ～。","ENG":"Nya hah hah... But I already told you before I debuted.","TWN":"喵哈哈～但我在出道前就已經說過了喵～"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"능력을 사용하고 나면 졸음이 무지 쏟아지는걸~♪","JPN":"能力を使ったあとは、ものすごく眠くなっちゃうのにゃ～♪","ENG":"Whenever I use my abilities, I get really sleepy. ♪","TWN":"我使用能力的時候，睡意會瞬間湧上來～♪"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"눈을 감으면 바로 꿈나라로 떠나 버린다구~♬","JPN":"目を閉じると、すぐに夢の国へ旅立てるにゃ～♬","ENG":"I'm off to dreamland the moment I close my eyes. ♬","TWN":"一旦閉上眼睛，馬上就會進入夢鄉～♬"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MANAGER_NPC_NULL_NULL","text":{"KOREA":"그건...... 어쩔 수 없었어.","JPN":"それは……仕方がなかったの。","ENG":"Well... We had no choice.","TWN":"這……我也沒辦法。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MANAGER_NPC_NULL_NULL","text":{"KOREA":"윗분들은 네 분신 능력을 퍼포먼스에 쓰길 원하니까. 카운터 중에서도 보기 드문 능력이고.","JPN":"お偉いさん達が、あなたの分身能力をパフォーマンスに使うことを望んだから。\\nカウンターにしても珍しい能力だからって。","ENG":"The big shots wanted you to use your cloning abilities as part of the performance. It's a rare skill even among Counters.","TWN":"畢竟上頭想讓妳把分身能力用在表演上。妳的能力就算在制裁者裡，也是非常稀有的。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MANAGER_NPC_NULL_NULL","text":{"KOREA":"미안해. 이제 와서 널 아무렇지 않게 팽개치려는 꼴이 싫지만......","JPN":"ゴメンね。今まで無理させておいて、見捨てるようなマネはしたくないのに……","ENG":"I'm sorry. I don't want you to feel like we're just abandoning you so easily after all you've done...","TWN":"對不起。事到如今，我也看不慣他們裝作若無其事，想要把妳踢出去的行為，但是……"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"매니저가 사과할 필요 없다는 사실! 알고 있지?","JPN":"マネージャーが謝ることはないのにゃ～！　そこんところ注意にゃ♪","ENG":"You don't need to apologize! You know that, right?","TWN":"經紀人不需要道歉！好嗎？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"내가 안 나가고 계속 버티면 다른 멤버들도 고생하지 않겠어?","JPN":"どうやらボミがグループに残ってると、他のメンバーが迷惑しそうだにゃ。","ENG":"If I stay, the other members will have a hard time, won't they?","TWN":"如果我一直堅持不退出的話，其他成員會很辛苦吧？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MANAGER_NPC_NULL_NULL","text":{"KOREA":"보미야, 그건......","JPN":"ボミ、あなた……","ENG":"Bomi, that's...","TWN":"普美，那是……"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"괜찮아~ 고양이는 눈치 빠른 동물이라구~","JPN":"平気だにゃ～。ネコは察しの良い動物なのにゃ～。","ENG":"It's okay! Cats are quick to catch onto what's really going on!","TWN":"沒關係啦～貓可是非常會察顏觀色的動物喔～"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MANAGER_NPC_NULL_NULL","text":{"KOREA":"......싫지 않아?","JPN":"……嫌じゃないの？","ENG":"Aren't you upset?","TWN":"……妳不會討厭嗎？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MANAGER_NPC_NULL_NULL","text":{"KOREA":"좋을 대로 써먹다가, 트집 좀 잡혔다고 아무렇지 않게 내치려는 사람들이......","JPN":"あの人達は、あなたを好き勝手に利用しておいて、ケチがついたからって切り離そうとしてるのに……","ENG":"Don't you hate us for taking advantage of you, only to cut you loose so easily just because of a little hiccup?","TWN":"隨心所欲地使喚別人，一有問題就想要若無其事拋棄妳的那群人……"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"어허~ 보미는 그런 일로 속상해하지 않는다구~","JPN":"はっずれ～♪　ボミはそんなことで落ち込んだりしないにゃ～。","ENG":"Aw, come on. I don't get upset over stuff like that.","TWN":"啊～普美不會因為這種事傷心的～"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"왜냐면 매니저를 따라와서 그동안 재밌게 지냈는걸~♬","JPN":"なぜならマネージャーが声をかけてくれたおかげで、今まで楽しかったからにゃ～♬","ENG":"I've had a great time here thanks to you. ♬","TWN":"而且與經紀人一起生活的這段時間，普美很開心喔～♬"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"그래도 취향 안 맞는 노래 부르라거나 따분한 예능 나가서 자리나 채우라는 요구는 너무 어렵단 말씀!","JPN":"ただ、趣味に合わないお歌を歌わされたり、\\nつまんない番組に出て数合わせで座ってるのはもう大変だったのにゃ！","ENG":"Still, it wasn't very fun having to sing songs I don't like, or be a placeholder in boring variety shows!","TWN":"而且，讓我去唱不喜歡的歌曲，或是在無聊的綜藝節目占個位置，這些對我來說實在是太難了！"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MANAGER_NPC_NULL_NULL","text":{"KOREA":"......그러네. 원없이 춤만 추면 된다고 했는데, 거짓말이 됐어.","JPN":"……そうね。好きに踊るだけでいいって誘ったのに、あなたを騙したことになってしまったわ。","ENG":"I know... I told you that all you needed to do is dance, but that turned out to be a lie.","TWN":"……是啊。當初會讓妳盡情跳舞的約定，現在也成為了謊言。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MANAGER_NPC_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MANAGER_NPC_NULL_NULL","text":{"KOREA":"조금 이른 얘기일 수도 있겠지만, 나가서 따로 하고 싶은 일은 없어?","JPN":"少し急すぎる話かもしれないけど、ここを出たら他にやりたいことはあるの？","ENG":"I guess it might be too soon, but is there anything you want to do once you're out of here?","TWN":"這話說得可能有點早，不過妳離開後有沒有什麼想做的事？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"당연히 사람들 앞에서 춤추는 일이지~","JPN":"もっちろん、みんなの前で踊ることがしたいにゃ～。","ENG":"Dancing in front of people, of course!","TWN":"當然是在人們面前跳舞啦～"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"춤을 추면 나도 재밌고, 보는 사람들도 좋아하고, 일석이조 아니겠어?","JPN":"踊るとボミも楽しいし、見てる人も盛り上がるし、一石二鳥だと思うのにゃ～。","ENG":"Dancing makes me happy and the people watching me too! Two birds with one stone!","TWN":"我很喜歡跳舞，人們也很喜歡看，這不是一石二鳥嗎？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"공연할 때는 매니저도 보러 와♬ 깜짝 놀랄 만큼 멋진 무대를 보여 줄 테니까♪","JPN":"マネージャーもステージを見に来てほしいにゃ♬　びっくりするくらい素敵なダンスを見せてあげるにゃ♪","ENG":"You should come watch me when I put on a show. ♬ I'll be sure to deliver knockout performances! ♪","TWN":"公演的時候經紀人也過來看吧♬我會打造一個能讓所有人驚歎的舞臺喵♪"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MANAGER_NPC_NULL_NULL","text":{"KOREA":"그래...... 넌 정말 한결같네.","JPN":"そうなの……あなたはずっと変わらないわね。","ENG":"Sure... I guess you haven't changed at all.","TWN":"好……妳還是跟以前一樣呢。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"어머, 얘. 오랜만이다. 일은 잘 되고?","JPN":"あら、あなたから連絡してくるなんて珍しいわね。仕事は順調なの？","ENG":"Oh, my. How long has it been? How's work been?","TWN":"哎呀。好久不見。工作順利嗎？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_UI_DECK_UNIIT_SELECT"},{"id":"L8_1","type":"dialog","speaker":"MANAGER_NPC_NULL_NULL","text":{"KOREA":"일이야 항상 그럭저럭이죠. 언니는 퇴직하고 요새 기획사 창업 준비하고 계신다면서요?","JPN":"まあ、いつも通りボチボチやっています。ハラジマさんは退職してご自身で事務所を立ち上げられるそうですね？","ENG":"Work is just work, as always. I heard you resigned and have been planning to start your own agency.","TWN":"馬馬虎虎吧。聽說姐姐離職後準備開一家企劃公司？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"후후, 소문 참 빠르기도 해라.","JPN":"フフ、噂ってあっという間に広がるのね。","ENG":"Hah hah, the word gets around fast, doesn't it?","TWN":"呵呵，消息傳得真快啊。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"그러는 넌 이번에 방출되는 아이 때문에 연락했겠네.","JPN":"ということは、今回契約を切られる子のことで連絡したんでしょ？","ENG":"And I bet you reached out to me because of the girl you guys are kicking out.","TWN":"那妳會聯絡我，一定是為了這次被趕出來的孩子吧。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MANAGER_NPC_NULL_NULL","text":{"KOREA":"어, 어떻게 아셨어요?","JPN":"な、なんでわかるんですか？","ENG":"H-how did you know?","TWN":"妳、妳是怎麼知道的"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"말했잖아. 소문 참 빠르다고.","JPN":"今言ったとおり、噂ってあっという間に広がるのよ。","ENG":"Like I said, the word gets around fast.","TWN":"我不是說過了嗎？消息傳播的速度是很快的。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"그리고 기왕 새 기획사를 차렸는데, 가능성 있는 아이들은 물색해 둬야지.","JPN":"それに、せっかく新しい事務所を立ち上げるんだもの。見込みのある子はチェックしておかないとね。","ENG":"Besides, I could always use fresh talent with this new agency I'm setting up.","TWN":"而且既然開了企劃公司，就必須去尋找有潛力的人才啊。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MANAGER_NPC_NULL_NULL","text":{"KOREA":"언니가 그렇게 말씀하시니까 더 아쉬워지네요.","JPN":"ハラジマさんにそう言われると、あの子と別れるのが余計に惜しくなりますね。","ENG":"That makes me realize even more what a loss it is for our agency...","TWN":"姐姐竟然會這麼說，我覺得更遺憾了呢。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"후훗. 너무 아쉬워하지 마.","JPN":"フフッ。別れは新しい出会いの始まりなのよ。","ENG":"Hah hah. Too late for that now.","TWN":"呵呵，你不用感到太遺憾。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"아, 저기 보이네. 미안. 보미랑 얘기해 봐야 돼서.","JPN":"あっ、ちょうど来てるわ。ごめんね、今からボミと話さなくちゃいけないの。","ENG":"Oh, there she is. Sorry. I'm going to need to talk it over with Bomi.","TWN":"啊，我看到她了。抱歉，我得去和普美談談了。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MANAGER_NPC_NULL_NULL","text":{"KOREA":"네? 언제 이 근처까지 찾아오셨어요?","JPN":"はい？　いつの間にこの辺りまで来られたんですか？","ENG":"What? When did you come around this part of town?","TWN":"咦？妳什麼時候找到這附近的？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"이 업계에서 순발력 빼면 뭐가 남겠니.","JPN":"この業界では瞬発力こそが命よ。","ENG":"Speed is of the essence in our line of work, sweetie.","TWN":"做這一行如果沒了爆發力，那還剩什麼？。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"그럼 끊는다? 얘기 끝나고 어떻게 됐는지 알려 줄게?","JPN":"それじゃ、もう切るわね。あとで結果を教えるわ。","ENG":"Alright, I'm hanging up now. I'll let you know how the talk went later.","TWN":"那我掛了喔。我和她談完後，要我告訴妳事情發展如何嗎？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MANAGER_NPC_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MANAGER_NPC_NULL_NULL","text":{"KOREA":"그래, 보미야. 기왕 이렇게 된 거......","JPN":"そうよ、ボミ。こうなったからには……","ENG":"This is good, Bomi... Now that it's come to this...","TWN":"沒錯，普美啊，既然事情已經變成這個樣子……"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MANAGER_NPC_NULL_NULL","text":{"KOREA":"꼭 잘 돼서, 윗분들 코를 납작하게 만들어 줘.","JPN":"絶対に成功して、お偉いさん方の鼻っ柱をへし折ってやるのよ。","ENG":"I hope you make it real big and make those big shots realize what a mistake they've made.","TWN":"就趁這次機會給上頭一點顏色瞧瞧吧。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};